    // C: case LUA_VUSERDATA: case LUA_VLIGHTUSERDATA: return touserdata(o);
    // C: default: if (iscollectable(o)) return gcvalue(o); else return NULL;
    // TODO(port): returning a raw pointer here is not safe outside lua-gc.
